from .stages.raster import RasterStage
from .stages.shade import ShadeStage

class RenderPipeline:
    def __init__(self, stages=None):
        self.stages = stages or [RasterStage(), ShadeStage()]
    def run(self, scene):
        for s in self.stages: s.apply(scene)
